def find_zero(xs: list):
    lo, hi = -1.0, 1.0
    f_lo, f_hi = poly(xs, lo), poly(xs, hi)

    while f_lo == 0:
        return lo
    while f_hi == 0:
        return hi

    while f_lo * f_hi > 0:
        lo *= 2
        hi *= 2
        f_lo, f_hi = poly(xs, lo), poly(xs, hi)

    for _ in range(100):
        mid = (lo + hi) / 2
        f_mid = poly(xs, mid)
        if f_mid == 0:
            return mid
        if f_lo * f_mid <= 0:
            hi, f_hi = mid, f_mid
        else:
            lo, f_lo = mid, f_mid

    return (lo + hi) / 2
