def minPath(grid, k):
    n = len(grid)
    if k == 1:
        return [min(min(row) for row in grid)]

    # Start from the smallest cell
    best = None
    for i in range(n):
        for j in range(n):
            if best is None or grid[i][j] < best[0]:
                best = (grid[i][j], i, j)

    path = [best[0]]
    frontier = {(best[1], best[2])}

    for _ in range(1, k):
        nxt = None
        new_frontier = set()
        for i, j in frontier:
            for di, dj in ((1, 0), (-1, 0), (0, 1), (0, -1)):
                ni, nj = i + di, j + dj
                if 0 <= ni < n and 0 <= nj < n:
                    val = grid[ni][nj]
                    if nxt is None or val < nxt:
                        nxt = val
                        new_frontier = {(ni, nj)}
                    elif val == nxt:
                        new_frontier.add((ni, nj))
        path.append(nxt)
        frontier = new_frontier

    return path

