        for nr, nc in ((r - 1, c), (r + 1, c), (r, c - 1), (r, c + 1)):
            if 0 <= nr < n and 0 <= nc < n:
                v = grid[nr][nc]
                if best is None or v < best:
                    best = v
                    best_pos = (nr, nc)
        r, c = best_pos
        path.append(best)

