def prod_signs(arr):
    if not arr:
        return None
    prod = 1
    total = 0
    for x in arr:
        total += abs(x)
        if x > 0:
            prod *= 1
        elif x < 0:
            prod *= -1
        else:
            prod *= 0
    return total * prod

