def separate_paren_groups(paren_string: str) -> List[str]:
    groups = []
    current = []
    depth = 0

    for ch in paren_string:
        if ch == ' ':
            continue
        current.append(ch)
        if ch == '(':
            depth += 1
        elif ch == ')':
            depth -= 1
            if depth == 0:
                groups.append(''.join(current))
                current = []

    return groups

