def is_multiply_prime(a):
    count = 0
    n = a
    p = 2
    while p * p <= n and count < 3:
        while n % p == 0:
            count += 1
            n //= p
            if count > 3:
                return False
        p += 1
    if n > 1:
        count += 1
    return count == 3

