def triples_sum_to_zero(l: list):
    n = len(l)
    for i in range(n - 2):
        seen = set()
        target = -l[i]
        for j in range(i + 1, n):
            if target - l[j] in seen:
                return True
            seen.add(l[j])
    return False

def triples_sum_to_zero(l: list):
    l = sorted(l)
    n = len(l)
    for i in range(n - 2):
        if i > 0 and l[i] == l[i - 1]:
            continue
        left, right = i + 1, n - 1
        while left < right:
            s = l[i] + l[left] + l[right]
            if s == 0:
                return True
            if s < 0:
                left += 1
            else:
                right -= 1
    return False

